What does the following program print?

```cpp
#include <iostream>

class Timer {
private:
    int m_seconds{ 0 };
public:
    void setSeconds(int s) {
        if (s < 0) s = 0;
        m_seconds = s;
    }
    int getSeconds() const { return m_seconds; }
};

int main() {
    Timer t;
    t.setSeconds(-10);
    std::cout << t.getSeconds() << '\n';
    t.setSeconds(5);
    std::cout << t.getSeconds() << '\n';
    return 0;
}
```

